from dataclasses import dataclassimport jsonimport pandas as pdfrom criresviz.common import OPACITYfrom criresviz.models.feature import find_active_regions@dataclass(slots=True)class Molecule:    name: str    wavelength: pd.Series    opacity: pd.Series    normalized_opacity: pd.Series    temperature: float    pressure: float    opacity_mode: str    source: str    '''    Properties    '''    @property    def wavelength_range(self):        return (            self.wavelength.min(),            self.wavelength.max(),        )            @property    def peak_wavelength(self):        return self.wavelength.iloc[            self.normalized_opacity.idxmax()        ]    '''    Methods    '''    def active_regions(self, threshold=0.15):        return find_active_regions(            self.wavelength,            self.normalized_opacity,            threshold,        )        @classmethod    def from_name(cls, name):            df = pd.read_csv(OPACITY / f"{name}.csv")            with open(OPACITY / f"{name}.json") as f:            metadata = json.load(f)            return cls(            name=name,            wavelength=df["wavelength_um"],            opacity=df["opacity"],            normalized_opacity=df["normalized_opacity"],            temperature=metadata["temperature"],            pressure=metadata["pressure"],            opacity_mode=metadata["opacity_mode"],            source=metadata["source"],        )    def plot(        self,        ax=None,        threshold=0.20,    ):            from criresviz.plotting import plot_molecule            return plot_molecule(            self,            ax=ax,            threshold=threshold,        )    def __str__(self):            wmin, wmax = self.wavelength_range            return (            "Molecule\n"            "──────────────────────────────\n"            f"Name:              {self.name}\n"            f"Temperature:       {self.temperature:.0f} K\n"            f"Pressure:          {self.pressure/1e5:.1f} bar\n"            f"Wavelength range:  {wmin:.2f}–{wmax:.2f} μm"        )        